import 'package:freezed_annotation/freezed_annotation.dart';

part 'verify_transaction_response.freezed.dart';
part 'verify_transaction_response.g.dart';

@freezed
abstract class VerifyTransactionResponse with _$VerifyTransactionResponse {
  @JsonSerializable(explicitToJson: true, fieldRename: FieldRename.none)
  const factory VerifyTransactionResponse({
    required String id,
  }) = _VerifyTransactionResponse;

  factory VerifyTransactionResponse.fromJson(Map<String, dynamic> json) =>
      _$VerifyTransactionResponseFromJson(json);
}

