// Dart imports:
import 'dart:convert';

// Project imports:
import 'package:baseball_detector_flutter/data/models/in_app_purchase/jws_transaction_decoded_payload.dart';

/// JWT (JWS) をデコードして JWSTransactionDecodedPayload に変換するユーティリティクラス
class JwsDecoder {
  /// JWT 文字列をデコードして JWSTransactionDecodedPayload オブジェクトに変換
  ///
  /// [jws] - Apple から受け取った JWT 文字列
  /// Returns: デコードされたトランザクション情報、デコードに失敗した場合は null
  static JWSTransactionDecodedPayload? decodeTransactionPayload(String jws) {
    final parts = jws.split('.');
    if (parts.length < 2) {
      return null;
    }

    // JWT のペイロード部分（2 番目のパート）を取得
    final payload = parts[1];

    // Base64 デコード用に正規化
    final normalizedPayload = base64.normalize(payload);

    // Base64 デコード
    final decodedBytes = base64.decode(normalizedPayload);

    // UTF-8 文字列に変換
    final decodedString = utf8.decode(decodedBytes);

    // JSON パース
    final decodedJson = json.decode(decodedString) as Map<String, dynamic>;

    // JWSTransactionDecodedPayload オブジェクトに変換
    return JWSTransactionDecodedPayload.fromJson(decodedJson);
  }

  /// JWT 文字列をデコードして生の JSON Map を返す
  ///
  /// [jws] - Apple から受け取った JWT 文字列
  /// Returns: デコードされた JSON Map、デコードに失敗した場合は null
  static Map<String, dynamic>? decodeToJson(String jws) {
    final parts = jws.split('.');
    if (parts.length < 2) {
      return null;
    }

    final payload = parts[1];
    final normalizedPayload = base64.normalize(payload);
    final decodedBytes = base64.decode(normalizedPayload);
    final decodedString = utf8.decode(decodedBytes);
    final decodedJson = json.decode(decodedString) as Map<String, dynamic>;

    return decodedJson;
  }
}

